import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "How do I read a tire size like 225/55R17?", a: "The three numbers decode as: 225 = section width in mm (the widest point of the tire). 55 = aspect ratio (sidewall height as a percentage of the width: 55% of 225mm = 123.75mm sidewall). R = radial construction (all modern tires). 17 = rim diameter in inches. So 225/55R17 means a 225mm-wide tire with a 55% aspect ratio on a 17-inch rim." },
  { q: "What is tire aspect ratio and why does it matter?", a: "Aspect ratio is the sidewall height as a percentage of the tire's section width. A 225/55 tire has a sidewall of 225  x  0.55 = 123.75mm. Lower aspect ratio (e.g., /40) = shorter, stiffer sidewall = better handling, worse ride comfort, more wheel damage risk. Higher ratio (e.g., /70) = taller sidewall = better ride comfort, more flex. Sports cars use 35-45; trucks/SUVs use 60-80." },
  { q: "What happens if I use the wrong tire size?", a: "Using a significantly different tire size can affect speedometer accuracy (circumference changes), fuel economy, handling, ground clearance, and may cause rubbing against the wheel well. Within one size step (e.g., 225/55 to 235/55 or 225/50) is usually acceptable. Always check circumference difference - staying within 3% of the original is the general guideline." },
  { q: "What is the overall diameter of a tire?", a: "Overall diameter = 2  x  sidewall height + rim diameter (converted to mm). For 225/55R17: sidewall = 225  x  0.55 = 123.75mm, rim = 17  x  25.4 = 431.8mm, diameter = 2  x  123.75 + 431.8 = 679.3mm (26.7 inches). This affects speedometer calibration - the speedometer reads based on expected revolutions per mile, which changes with tire diameter." },
  { q: "How does tire size affect my speedometer?", a: "Your speedometer is calibrated for your stock tire's circumference. A larger diameter tire rotates fewer times per mile, making the speedometer read lower than actual speed (you're going faster than it shows). A smaller tire reads higher than actual. As a rule: every 1.8% change in circumference = ~1 mph error at 60 mph indicated. This calculator shows revolutions per mile to help compare." },
  { q: "What is the difference between the rim diameter and tire diameter?", a: "Rim diameter is the inner diameter of the tire (where it seats on the wheel) - expressed in inches. Tire (overall) diameter is the full outer diameter including the rim and both sidewalls. For 225/55R17: rim = 17 inches, but overall tire diameter = 26.7 inches. These are very different measurements. When people say 'bigger wheels,' they usually mean larger rim diameter, often paired with a lower profile tire to keep overall diameter similar." },
  { q: "What does plus-sizing mean in tire sizing?", a: "Plus-sizing means going to a larger rim diameter while reducing the tire's aspect ratio to maintain roughly the same overall tire diameter. Example: upgrading from 205/65R15 to 225/50R17. The overall circumference stays similar so the speedometer reads correctly. Plus-sizing improves handling response and aesthetics but can increase road noise and harshness." },
  { q: "How do I find replacement tires for my vehicle?", a: "Check the sticker inside your driver's door jamb - it shows the OEM (factory) tire size and recommended pressure. Your owner's manual also lists approved sizes. Many online tire retailers have fitment guides. When replacing, match the load index and speed rating (letters after the rim diameter, e.g., 225/55R17 97H - 97 = load index, H = speed rating up to 130 mph)." },
];

const COMMON_TIRE_SIZES = [
  ["195/65R15", "195", "65", "15", "24.2\"", "804"],
  ["205/55R16", "205", "55", "16", "24.9\"", "831"],
  ["225/55R17", "225", "55", "17", "26.7\"", "774"],
  ["235/45R18", "235", "45", "18", "26.4\"", "784"],
  ["245/40R19", "245", "40", "19", "26.7\"", "774"],
  ["265/70R17", "265", "70", "17", "31.6\"", "655"],
  ["275/55R20", "275", "55", "20", "31.9\"", "649"],
];

export default function TireSizeCalculator() {
  const [width, setWidth] = useState(225);
  const [aspect, setAspect] = useState(55);
  const [rimIn, setRimIn] = useState(17);

  const sidewallMm = width * (aspect / 100);
  const rimMm = rimIn * 25.4;
  const overallDiamMm = 2 * sidewallMm + rimMm;
  const overallDiamIn = overallDiamMm / 25.4;
  const circumMm = Math.PI * overallDiamMm;
  const circumIn = circumMm / 25.4;
  const revPerMile = (5280 * 12) / circumIn;

  return (
    <>
      <SEOHead
        title="Free Tire Size Calculator Online - Decode Any Tire Size Code Instantly | CalcHive"
        description="Free online tire size calculator. Decode any tire size code to find overall diameter, sidewall height and circumference instantly. 100% free for every driver, no signup required."
        canonical="/tire-size-calculator"
        keywords="free tire size calculator, tire size decoder free online, tire diameter calculator free, sidewall height calculator free, decode tire size code free"
        category="Automotive Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-rose-600 dark:text-rose-400 bg-rose-50 dark:bg-rose-950/50 px-3 py-1 rounded-full mb-4 inline-block">Transportation</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Tire Size Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free tire size calculator to decode tire size code free and find diameter, sidewall height, and circumference instantly. This tire size decoder free online also works as a tire diameter calculator free and sidewall height calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="bg-accent/60 border border-border rounded-xl px-4 py-3 text-center mb-6">
            <p className="text-3xl font-black text-foreground tracking-wide">{width}/{aspect}R{rimIn}</p>
            <p className="text-xs text-muted-foreground mt-1">Width / Aspect Ratio R Rim</p>
          </div>
          <div className="space-y-6 mb-8">
            <SliderInput id="width" label="Tire Width (mm)" value={width} min={135} max={335} step={5} onChange={setWidth} format={v => `${v} mm`} testId="input-width" helpText="First number in tire code (e.g., 225)" />
            <SliderInput id="aspect" label="Aspect Ratio (%)" value={aspect} min={25} max={80} step={5} onChange={setAspect} format={v => `${v}%`} testId="input-aspect" helpText="Second number in tire code (e.g., 55)" />
            <SliderInput id="rim" label="Rim Diameter (inches)" value={rimIn} min={13} max={26} step={1} onChange={setRimIn} format={v => `${v}"`} testId="input-rim" helpText="Number after 'R' in tire code (e.g., 17)" />
          </div>
          <motion.div key={`${width}-${aspect}-${rimIn}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-rose-500 to-rose-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Overall Tire Diameter</p>
              <p className="text-5xl font-black text-white tracking-tight" data-testid="result-diameter">{overallDiamIn.toFixed(2)}"</p>
              <p className="text-white/70 text-sm mt-1">{overallDiamMm.toFixed(1)} mm</p>
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
              {[
                { label: "Sidewall Height", value: `${sidewallMm.toFixed(1)} mm / ${(sidewallMm/25.4).toFixed(2)}"` },
                { label: "Circumference", value: `${circumIn.toFixed(2)}" / ${circumMm.toFixed(0)} mm` },
                { label: "Revs per Mile", value: revPerMile.toFixed(0) },
                { label: "Rim Diameter", value: `${rimIn}" / ${rimMm.toFixed(0)} mm` },
              ].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-3 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-sm font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Decode Any Tire Size Code for Free</h2>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Sidewall Height (mm) = Width  x  (Aspect Ratio  x  100)</p>
            <p>Rim (mm) = Rim Diameter (in)  x  25.4</p>
            <p>Overall Diameter (mm) = 2  x  Sidewall + Rim (mm)</p>
            <p>Circumference (in) = pi  x  Overall Diameter (in)</p>
            <p>Revs per Mile = (5,280  x  12)  x  Circumference (in)</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Find Tire Diameter Sidewall Height and Circumference</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Tire Size", "Width (mm)", "Aspect", "Rim (in)", "Diameter", "Revs/Mile"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {COMMON_TIRE_SIZES.map(([size, w, a, r, diam, revs]) => {
                  const current = parseInt(w) === width && parseInt(a) === aspect && parseInt(r) === rimIn;
                  return (
                    <tr key={size} className={`hover:bg-muted/30 ${current ? "bg-rose-50 dark:bg-rose-950/20 font-semibold" : ""}`}>
                      <td className="py-2.5 px-4 font-bold text-rose-600 dark:text-rose-400">{size}</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{w}</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{a}%</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{r}"</td>
                      <td className="py-2.5 px-4 font-semibold text-foreground">{diam}</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{revs}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Tire Size Decoder for Every Driver</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free automotive tool on mobile or desktop to compare vehicle scenarios quickly and make clearer driving or maintenance estimates.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/tire-size-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


